import torch


def torch_relu_unit_vector(values: list[float]) -> list[float]:
    tensor = torch.tensor(values, dtype=torch.float32)
    activated = torch.relu(tensor)
    norm = torch.linalg.vector_norm(activated)
    if float(norm) == 0.0:
        return activated.tolist()
    return (activated / norm).tolist()
